OUT = os.path.join(os.path.dirname(__file__), '..', 'data', 'books', 'introductions')

ENRICHMENTS = {
  "philippians": {
    "key_people": [
      {"name": "Paul", "role": "Writing from prison (1:7, 13-14, 17), he uses his own experience of contentment in every circumstance (4:11-13) as the personal embodiment of the letter's call to rejoice"},
      {"name": "Timothy", "role": "Paul's closest co-worker, commended for genuinely caring for the Philippians' interests rather than his own (2:19-22) — a living example of the mind of Christ the letter calls for"},
      {"name": "Epaphroditus", "role": "The Philippians' messenger who nearly died in Rome while serving Paul; his recovery and return with the letter is the occasion that prompts Paul's extended thanks"},
      {"name": "Euodia and Syntyche", "role": "Two women who laboured with Paul in the gospel but are now at odds; the letter's call to unity is ultimately aimed at their specific reconciliation (4:2-3)"}
    ],
    "context": "Philippians was written c. AD 60-62 from Rome during Paul's imprisonment, to the first European church he founded (Acts 16:12-40). The Philippian church was his most personally warm relationship — the only church from which he accepted financial support (4:15-16). The letter's occasion is a thank-you for the Philippians' gift sent with Epaphroditus, expanded into a pastoral letter addressing divisions and anxiety.",
    "christ_connection": "The Christ-hymn of Philippians 2:5-11 is the NT's most concise and lyrical account of the Incarnation and its purpose: the one who was in the form of God emptied himself, took the form of a servant, became obedient to death, even death on a cross — and was therefore exalted to the highest place. This movement from exaltation to humiliation to exaltation is both the gospel story and the pattern for Christian ethics: 'have this mind among yourselves, which is yours in Christ Jesus' (2:5). The 'surpassing worth' of knowing Christ (3:8) is Paul's summary of why he counts everything else as loss.",
    "key_verses": [
      {"ref": "Philippians 1:21", "note": "'For to me to live is Christ, and to die is gain' — Paul's personal summary of the Christ-centred orientation that makes contentment in every circumstance possible"},
      {"ref": "Philippians 2:6-7", "note": "'Who, though he was in the form of God, did not count equality with God a thing to be grasped, but emptied himself' — the theological heart of the kenosis hymn"},
      {"ref": "Philippians 4:7", "note": "'The peace of God, which surpasses all understanding, will guard your hearts and your minds in Christ Jesus' — the promised result of prayer over anxiety"},
      {"ref": "Philippians 4:13", "note": "'I can do all things through him who strengthens me' — in context, the ability to be content in abundance and in need, not a general promise of unlimited ability"}
    ],
    "themes_detail": [
      {"title": "Joy as the Theological Fruit of Christ-Centredness", "text": "Philippians is the NT's letter of joy — the word occurs 16 times in four chapters. What is remarkable is the context: Paul is in prison, facing possible execution (1:20-23), and the church is experiencing conflict (4:2) and opposition (1:28). Joy in Philippians is not a mood but a theological orientation — the result of fixing one's entire being on Christ rather than on circumstances. Paul's joy is not despite his imprisonment but because his imprisonment has advanced the gospel (1:12-14). This is the logic of 4:11-13: contentment is learned, not given, and its teacher is the one who strengthens."},
      {"title": "The Mind of Christ as the Pattern for Community Life", "text": "The Christ-hymn (2:5-11) is embedded in a pastoral argument: the Philippians are to have the same mind, the same love, the same accord (2:2), and the model for this corporate orientation is the mind of Christ who did not grasp equality with God but poured himself out for others. Chapters 2-4 then provide living examples of this mind: Timothy who looks to others' interests (2:20-21), Epaphroditus who risked his life in service (2:30), Paul who counts everything loss for Christ (3:7-8). The letter argues its ethical point not by command alone but by narrative illustration."},
      {"title": "Righteousness by Faith and the Warning Against Confidence in the Flesh", "text": "Chapter 3 addresses the danger of false teachers who are demanding circumcision and Torah observance for full membership in God's people — the same problem as Galatians but approached pastorally rather than polemically. Paul turns his own impressive credentials (3:4-6) into a testimony of loss: everything he once counted as gain he now counts as rubbish for the surpassing worth of knowing Christ. The righteousness he seeks is not from the law but through faith in Christ (3:9). The contrast between earthly-minded people (3:19) and citizens of heaven awaiting Christ (3:20-21) is the eschatological framework for this argument."},
      {"title": "Anxiety, Prayer, and the Peace that Guards", "text": "Philippians 4:4-9 is the NT's most comprehensive treatment of the alternative to anxiety: rejoice in the Lord always, let your reasonableness be known to everyone, pray with thanksgiving about everything, and think about what is true, honourable, just, pure, lovely, commendable. The result is not the removal of difficulty but 'the peace of God, which surpasses all understanding' (4:7). This peace 'guards' hearts and minds — military language for a protective garrison. Paul's own contentment-in-every-circumstance (4:11) is not natural temperament but the fruit of learning the secret through the one who strengthens him."}
    ]
  },

  "colossians": {
    "key_people": [
      {"name": "Paul", "role": "Author writing from prison; Colossians has significant overlap with Ephesians and may represent a more targeted version of the same theological vision addressed to a specific false-teaching crisis"},
      {"name": "Epaphras", "role": "The founder of the Colossian church (1:7) and Paul's source of information about its situation; his prayer for the Colossians (4:12) is described in terms of intense spiritual labour"},
      {"name": "Onesimus", "role": "Mentioned alongside Tychicus (4:9) and the letter to Philemon — his presence ties Colossians to the Philemon correspondence and the story of the runaway slave"}
    ],
    "context": "Colossians was written c. AD 60-62 from prison, to a church Paul had not personally founded in the Lycus Valley of Asia Minor. The specific threat was a 'philosophy' (2:8) that combined Jewish calendar observances, angelic intermediaries, and ascetic practices, apparently encouraging the Colossians to supplement their faith in Christ with these additional spiritual practices. Paul's response is the most developed NT account of Christ's cosmic supremacy.",
    "christ_connection": "Colossians 1:15-20 is the NT's most comprehensive statement of Christ's cosmic lordship: he is the image of the invisible God, the firstborn of all creation, the agent of creation for all things visible and invisible, the head of the body the church, the firstborn from the dead, and the one in whom the fullness of God was pleased to dwell. This hymn is Paul's christological argument against the Colossian philosophy: there is no spiritual reality that is not already subject to Christ, no angelic mediator that competes with him, and no religious practice that can add to what is found in him.",
    "key_verses": [
      {"ref": "Colossians 1:15", "note": "'He is the image of the invisible God, the firstborn of all creation' — the opening of the Christ-hymn establishing Christ's ontological priority over all creation"},
      {"ref": "Colossians 1:19", "note": "'In him all the fullness of God was pleased to dwell' — the claim that leaves no room for supplementary spiritual mediators: the totality of deity resides in Christ"},
      {"ref": "Colossians 2:9-10", "note": "'The whole fullness of deity dwells bodily, and you have been filled in him, who is the head of all rule and authority' — the application: if Christ is full, those in him are full; nothing more is needed"},
      {"ref": "Colossians 3:3", "note": "'For you have died, and your life is hidden with Christ in God' — the indicative foundation for all the imperatives that follow in chapters 3-4"}
    ],
    "themes_detail": [
      {"title": "The Cosmic Supremacy of Christ", "text": "The Christ-hymn (1:15-20) establishes Christ's lordship over two domains: the original creation (1:15-17) and the new creation (1:18-20). In both domains, Christ is supreme: he is the agent and goal of creation ('all things were created through him and for him', 1:16), and the reconciler of all things through his cross (1:20). The hymn's scope is explicitly cosmic: 'all things, whether on earth or in heaven' (1:20). This is Paul's fundamental argument against any philosophy that adds supplementary spiritual requirements: if Christ is supreme over every power, every domain, and every element of the cosmos, nothing stands above him to require additional mediation."},
      {"title": "Fullness in Christ Alone", "text": "The Colossian philosophy apparently offered spiritual fullness through additional practices (2:16, 18, 23). Paul's response is the repeated assertion that fullness already resides entirely in Christ (1:19; 2:9) and that believers are already complete in him (2:10). The gospel does not give a down payment that must be supplemented by religious experiences, angelic encounters, or ascetic discipline. These practices, Paul argues, have an appearance of wisdom but no genuine power over the flesh (2:23) — they address symptoms, not causes. The only source of genuine transformation is the crucified, risen, and supremely exalted Christ."},
      {"title": "The Hidden Life and the Visible Life", "text": "Colossians 3 builds its ethics on a single indicative: 'you have died, and your life is hidden with Christ in God' (3:3). The Christian's true identity is not what is currently visible but what will be revealed when Christ appears (3:4). This hidden-life theology is the foundation for the following imperatives: 'put to death' what is earthly (3:5), 'put off' the old self (3:9), 'put on' the new self (3:10). The new self is 'being renewed in knowledge after the image of its creator' (3:10) — the same image-language as the Christ-hymn (1:15). Christians are being conformed to the image of the one who is the image of God."},
      {"title": "The Household Code and the Lordship of Christ", "text": "Colossians 3:18-4:1 grounds every household relationship in the lordship of Christ. Children obey parents 'in the Lord' (3:20); slaves work 'for the Lord' (3:23-24); masters treat slaves justly because they have 'a Master in heaven' (4:1). The motivating principle throughout is the reality that Christ is Lord of every sphere of life — family, work, and social relations are not secular domains but places where the lordship of Christ is expressed and contested. The 'as to the Lord' refrain (3:18, 23) is not merely a pious decoration but the governing theological principle of an entirely Christocentric ethics."}
    ]
  },

  "1thessalonians": {
    "key_people": [
      {"name": "Paul, Silas, and Timothy", "role": "The three co-authors who founded the Thessalonian church during Paul's second missionary journey (Acts 17:1-9) and whose pastoral concern for the young church pervades the letter"},
      {"name": "The Thessalonian Believers", "role": "Described as having 'turned to God from idols' (1:9) — a Gentile conversion that serves as a model for all the churches of Macedonia and Achaia"}
    ],
    "context": "1 Thessalonians is probably Paul's earliest surviving letter, written c. AD 50-51 from Corinth shortly after a forced departure from Thessalonica (Acts 17:5-9). Timothy has returned with good news of the church's faith and love (3:6), and Paul writes to address their grief about believers who have died before the Lord's return and to encourage continued growth in holiness.",
    "christ_connection": "The letter's eschatology is entirely Christ-centred: the hope that transforms grief is the resurrection of Jesus himself ('since we believe that Jesus died and rose again', 4:14) and his personal return. The dead in Christ will rise first; the living will be caught up together with them to meet the Lord in the air; and the result is simply 'we will always be with the Lord' (4:17). This is the pastoral anchor: the goal of resurrection is not a state but a person. The patience of hope (1:3) is the hope of his coming; holiness is sanctification at the coming of the Lord Jesus Christ (5:23).",
    "key_verses": [
      {"ref": "1 Thessalonians 1:9-10", "note": "The summary of conversion: turned from idols to serve the living God and to wait for his Son from heaven — faith, love, and hope defined in relation to the living God and the returning Christ"},
      {"ref": "1 Thessalonians 4:13-14", "note": "'We do not want you to be uninformed, brothers, about those who are asleep, that you may not grieve as others do who have no hope. For... Jesus died and rose again' — the resurrection as the answer to grief"},
      {"ref": "1 Thessalonians 5:16-18", "note": "'Rejoice always, pray without ceasing, give thanks in all circumstances; for this is the will of God in Christ Jesus for you' — the most compressed description of the Christian's basic posture toward God"}
    ],
    "themes_detail": [
      {"title": "The Model Church and the Power of the Gospel", "text": "1 Thessalonians 1:2-10 is a sustained meditation on what genuine gospel transformation looks like: the word came 'not only in word, but also in power and in the Holy Spirit and with full conviction' (1:5); the believers received it with joy despite suffering (1:6); and the faith of the Thessalonians has 'rung out' throughout Macedonia and Achaia so that Paul does not even need to say anything (1:8). This is Paul's portrait of an authentic church: not impressive programs or strategic communication, but a community whose visible transformation by the gospel is its own testimony."},
      {"title": "Pastoral Care and the Heart of Ministry", "text": "Chapters 2-3 contain the most extended pastoral self-reflection in Paul's letters. His ministry in Thessalonica was characterised by gentleness (like a nursing mother, 2:7), personal affection (you were dear to us, 2:8), and parental investment (like a father with his children, 2:11-12). His forced separation from them was like being 'orphaned' (2:17); he sent Timothy because he could not bear not knowing how they were (3:1-5); Timothy's report of their faith and love consoled him in all his distress (3:6-8). This is Paul's account of what genuine ministry relationships look like: deeply personal, emotionally invested, and motivated entirely by the wellbeing of the flock."},
      {"title": "Holiness as God's Will and the Spirit's Work", "text": "Chapter 4:1-12 addresses holiness — specifically sexual holiness — with a directness that reflects the sharp contrast between Christian ethics and Greco-Roman sexual practice. God's will is 'your sanctification' (4:3), which includes controlling one's body in holiness and honour rather than in lustful passion (4:4-5). The motivation is not mere rule-following but the reality of God's call to holiness and the Spirit given to enable it (4:7-8). The implication: rejecting Paul's instruction about sexual ethics is not merely rejecting a human preference but rejecting the God who gives his Holy Spirit."},
      {"title": "The Return of Christ and the Resurrection of the Dead", "text": "The longest single section (4:13-5:11) addresses the Thessalonians' anxiety about believers who have died. Paul's answer transforms their grief: those who have died in Christ will not miss out on the resurrection — they will rise first. The description of the parousia (4:16-17) is vivid and structured: the cry of command, the archangel's voice, the trumpet of God, the rising of the dead, the gathering of the living — all culminate in the promise 'we will always be with the Lord.' The eschatological hope is not an abstraction about heaven but the personal presence of the returning Christ. This hope is the foundation for mutual encouragement (4:18; 5:11)."}
    ]
  },

  "2thessalonians": {
    "key_people": [
      {"name": "Paul, Silas, and Timothy", "role": "The same triad as 1 Thessalonians, addressing the same church with a follow-up that corrects a specific misunderstanding about the Day of the Lord"}
    ],
    "context": "2 Thessalonians was written c. AD 51, shortly after the first letter, to address two problems: the Thessalonians are being shaken by claims that the Day of the Lord has already come (2:2), and some members are living in idleness on the basis of this misguided eschatology (3:6-15). The letter provides both a corrected eschatological timetable and a practical corrective to the disorder the misunderstanding has caused.",
    "christ_connection": "The letter's opening vision of Christ's return (1:7-10) is the NT's most explicit statement of judgment at the parousia: the Lord Jesus is revealed from heaven with his mighty angels in flaming fire, inflicting vengeance on those who do not know God and do not obey the gospel. This judgment-side of the return is inseparable from its comfort-side (1:7): the same coming that brings destruction to Christ's enemies brings relief to his persecuted people. The restrainer who holds back the man of lawlessness (2:6-7) and the Lord Jesus who will kill him with the breath of his mouth (2:8) both establish that history's outcome is entirely in Christ's hands.",
    "key_verses": [
      {"ref": "2 Thessalonians 1:7-8", "note": "Christ revealed from heaven in flaming fire, bringing vengeance on those who do not know God — the letter's opening eschatological vision that reframes the Thessalonians' current suffering"},
      {"ref": "2 Thessalonians 2:3-4", "note": "The man of lawlessness who opposes and exalts himself above every so-called god — the precursor whose coming must happen before the Day of the Lord"},
      {"ref": "2 Thessalonians 3:10", "note": "'If anyone is not willing to work, let him not eat' — the apostolic rule addressing the idleness that eschatological misunderstanding had produced in the community"}
    ],
    "themes_detail": [
      {"title": "The Day of the Lord: Corrected Eschatology", "text": "Someone had claimed, possibly in a letter purporting to be from Paul, that the Day of the Lord had already come (2:2). Paul corrects this by listing two things that must happen first: the apostasy and the revelation of the man of lawlessness (2:3-4). The restrainer who currently holds back the lawless one must be removed before he is revealed (2:6-7). Whether the restrainer is the Roman Empire, the preaching of the gospel, or the Spirit (interpretations all have ancient support), the point is clear: the Day has not come, and believers should not be shaken by claims that it has. The pattern of history before the end is clarified so that the community can stand firm."},
      {"title": "Suffering, Judgment, and the Justice of God", "text": "2 Thessalonians 1:5-10 addresses the Thessalonians' suffering at the hands of persecutors with a theology of divine justice: their endurance is evidence of God's righteous judgment; God will repay their persecutors with affliction and give rest to the afflicted when Christ returns. This is not vengeance theology but covenant theology: the God who is just will act in accordance with his character, and his people's suffering is not a sign that he has abandoned them but a participation in Christ's own pattern of suffering before vindication. The prospect of Christ's return does not excuse withdrawal from work; it grounds patient endurance."},
      {"title": "The Man of Lawlessness and the Pattern of Evil", "text": "The figure of the man of lawlessness (2:3-12) is the NT's most concentrated description of eschatological evil. He opposes and exalts himself above God, takes his seat in the temple, claims to be God, and performs false signs and wonders. His coming is the work of Satan, and his deception succeeds with 'those who are perishing because they refused to love the truth' (2:10). The theological claim is significant: final apostasy is not intellectual mistake but wilful refusal of truth, for which people are responsible. God's sending of a 'strong delusion' (2:11) is judicial hardening — the same pattern as Pharaoh and the sin of persistent unbelief."},
      {"title": "Work, Order, and the Responsibilities of Community Life", "text": "The practical corrective of chapter 3 is addressed to those who had used eschatological excitement as a reason to stop working and become dependent on others. Paul's response is blunt: if anyone is unwilling to work, let him not eat (3:10). He cites his own example of working with his hands to provide for himself, not as an indulgence but as a model (3:7-9). The theological principle is not a work ethic for its own sake but the responsibility of community members to contribute rather than be burdens. Waiting for the Lord's return is not passive withdrawal but faithful engagement with the world God has given us to inhabit."}
    ]
  },

  "1timothy": {
    "key_people": [
      {"name": "Paul", "role": "Writing to his young associate with practical instructions for organising church life — the letter has a mentor-to-apprentice quality that is evident in its personal asides and encouragements"},
      {"name": "Timothy", "role": "Paul's closest associate who is now serving as Paul's representative in Ephesus (1:3); his youth (4:12), temperament (2 Tim 1:7), and pastoral responsibilities make this letter an extended guide to his ministry"}
    ],
    "context": "1 Timothy was written c. AD 62-65, after Paul's release from the Roman imprisonment of Acts 28, to Timothy who has been left in Ephesus to deal with false teachers. The letter's purpose is stated explicitly: 'so that you may know how one ought to behave in the household of God, which is the church of the living God, a pillar and buttress of the truth' (3:15). The Pastoral Epistles (1-2 Timothy and Titus) represent Paul's instructions for ordering the institutional life of the post-apostolic church.",
    "christ_connection": "The 'trustworthy saying' at the letter's heart (1:15 — 'Christ Jesus came into the world to save sinners, of whom I am the foremost') is Paul's personal summary of the gospel, all the more powerful for its self-implicating honesty. The one mediator between God and humanity, the man Christ Jesus, who gave himself as a ransom for all (2:5-6) is the theological foundation for the universal scope of prayer (2:1-4). The 'mystery of godliness' doxology (3:16) is one of the most comprehensive christological summaries in the NT: manifested in flesh, vindicated by the Spirit, seen by angels, proclaimed among nations, believed on in the world, taken up in glory.",
    "key_verses": [
      {"ref": "1 Timothy 1:15", "note": "'Christ Jesus came into the world to save sinners, of whom I am the foremost' — the gospel in its most personally grounded form; Paul's own testimony as the paradigm of grace"},
      {"ref": "1 Timothy 2:5", "note": "'For there is one God, and there is one mediator between God and men, the man Christ Jesus, who gave himself as a ransom for all' — the christological basis for universal prayer"},
      {"ref": "1 Timothy 3:15", "note": "The church as 'a pillar and buttress of the truth' — the letter's ecclesiological thesis: the church's primary identity is as guardian and public display of God's truth"}
    ],
    "themes_detail": [
      {"title": "Sound Doctrine and the Health of the Church", "text": "1 Timothy uses the phrase 'sound teaching' (or 'sound words' / 'sound doctrine') repeatedly — a medical metaphor: healthy teaching produces healthy faith; diseased teaching corrupts. The false teachers at Ephesus (1:3-7; 4:1-3; 6:3-10, 20-21) are identified not by detailed doctrinal refutation but by their character and fruit: they devote themselves to myths, genealogies, and controversies; they are arrogant, knowing nothing; their teaching leads to disorder and materialism. The contrast between healthy and diseased teaching is primarily ethical in manifestation, even if theological in root."},
      {"title": "The Ordering of Church Life", "text": "Chapters 2-3 provide detailed guidance for two aspects of church life: worship (prayer, appropriate conduct, the roles of men and women, 2:1-15) and leadership (the qualifications for overseers and deacons, 3:1-13). The detailed character qualifications for church leaders — above reproach, husband of one wife, sober-minded, self-controlled, respectable, hospitable, able to teach — prioritise character above competence. This is not bureaucratic organisation but theological conviction: the church's leadership is to embody the gospel, not merely administer an institution."},
      {"title": "Godliness and Contentment as Great Gain", "text": "Chapter 6's extended treatment of wealth and contentment (6:3-10, 17-19) addresses the false teachers' materialism and the broader Ephesian context of a prosperous city. Paul's principle is that godliness with contentment is itself great gain (6:6) — the person who has God and enough has everything of real value. The love of money (not money itself) is the root of all kinds of evil (6:10), and the wealthy are not to trust in uncertain riches but in God who richly provides (6:17). The alternative to materialism is not poverty but generosity: being rich in good works, sharing liberally (6:18)."},
      {"title": "Timothy's Personal Conduct and Vocation", "text": "The letter is punctuated by direct personal charges to Timothy himself: do not neglect the gift in you (4:14); train yourself for godliness (4:7-8); let no one despise your youth (4:12); keep yourself pure (5:22); flee the love of money (6:11); fight the good fight of faith (6:12). These charges reveal that Paul is not merely providing institutional guidelines but mentoring a young pastor in the interior life that public ministry requires. The 'man of God' (6:11) Timothy is called to be is not merely an administrator but a person whose faith, love, steadfastness, and gentleness make his teaching credible."}
    ]
  },

  "2timothy": {
    "key_people": [
      {"name": "Paul", "role": "Writing his final letter from a more severe Roman imprisonment (4:6-8, 16-18), with the awareness that death is near — 2 Timothy is his personal farewell and most urgent pastoral charge"},
      {"name": "Timothy", "role": "Called to come to Paul quickly (4:9, 21) and to carry on the ministry without shame — the letter functions as a passing of the baton from the dying apostle to his most trusted associate"}
    ],
    "context": "2 Timothy was written c. AD 66-67 from a Roman prison during Nero's persecution, probably as Paul's final letter before his execution. The tone is urgent and personal: everyone in Asia has abandoned him (1:15), only Luke is with him (4:11), and he expects death imminently (4:6-8). Despite this, the letter is an exhortation to courageous ministry and a passionate charge to guard the deposit of the faith.",
    "christ_connection": "The 'trustworthy saying' of 2:11-13 is the letter's christological centre: 'if we have died with him, we will also live with him; if we endure, we will also reign with him; if we deny him, he also will deny us; if we are faithless, he remains faithful.' Christ's faithfulness is the ultimate ground of hope — even our unfaithfulness cannot negate his character. The resurrection of Jesus Christ, risen from the dead, descended from David (2:8), is Paul's summary of the gospel for which he suffers. The 'deposit' entrusted to Timothy (1:12, 14; 2:2) is the gospel, and Christ's faithfulness guarantees that the one who guards the deposit can rely on the one who ultimately holds it.",
    "key_verses": [
      {"ref": "2 Timothy 1:12", "note": "'I know whom I have believed, and I am convinced that he is able to guard until that day what has been entrusted to me' — Paul's confidence in the face of death rests on the character of Christ, not his own performance"},
      {"ref": "2 Timothy 2:15", "note": "'Do your best to present yourself to God as one approved, a worker who has no need to be ashamed, rightly handling the word of truth' — the call to faithful, careful biblical exposition"},
      {"ref": "2 Timothy 3:16-17", "note": "'All Scripture is breathed out by God and profitable for teaching, for reproof, for correction, and for training in righteousness' — the most explicit NT statement of Scripture's divine inspiration and practical sufficiency"}
    ],
    "themes_detail": [
      {"title": "Courageous Ministry in the Face of Abandonment", "text": "The letter's emotional gravity comes from Paul's isolation (only Luke is with him, 4:11) and the specific note that 'everyone in Asia turned away from me' (1:15). Against this background, the charges to Timothy to 'not be ashamed of the testimony about our Lord, nor of me his prisoner' (1:8) and to 'share in suffering for the gospel' (1:8) are not abstract ideals but urgent personal appeals. Paul is not calling Timothy to theoretical courage but to the specific courage of standing publicly with a condemned prisoner when everyone else has withdrawn. The letter is a call to loyalty in the face of social pressure."},
      {"title": "The Guard and Transmission of the Gospel", "text": "The 'deposit' language (1:12, 14; compare 1 Tim 6:20) describes the gospel as a precious trust to be guarded intact and transmitted faithfully. Paul's charge to Timothy (2:2) establishes a four-generation chain: Paul to Timothy to faithful men who are able to teach others. This is the NT's clearest description of the apostolic tradition's transmission — not by institutional hierarchy alone but by personal discipleship in which the content of the gospel (what Paul heard from the apostle and entrusted to Timothy) is preserved through trusted teachers. Scripture guards the deposit by providing the standard against which teaching is measured."},
      {"title": "Scripture's Inspiration and Sufficiency", "text": "2 Timothy 3:14-17 grounds Timothy's confidence in the face of the 'difficult times' of the last days (3:1-9): he has known the sacred writings from childhood, and all Scripture is breathed out by God — a claim that grounds Scripture's authority in its divine origin. The fourfold utility (teaching, reproof, correction, training in righteousness) is comprehensive: Scripture is sufficient for every aspect of the minister's work. The 'man of God' who is equipped by Scripture requires nothing beyond it for his complete preparation. This does not exclude human wisdom but establishes the norm against which all human teaching is measured."},
      {"title": "The Finished Course and the Crown of Righteousness", "text": "2 Timothy 4:6-8 is the NT's most moving personal testimony: Paul has poured himself out as an offering; the time of his departure has come; he has fought the good fight, finished the race, kept the faith. The crown of righteousness awaiting him is laid up by the righteous Judge, who will award it on the Last Day not only to Paul but to all who have loved his appearing. This passage has consoled Christians facing death for nearly two thousand years precisely because Paul is not claiming achievement but receiving grace: the crown of righteousness is awarded by the Judge, not earned by the fighter. The race ends not in exhaustion but in expectation."}
    ]
  },

  "titus": {
    "key_people": [
      {"name": "Paul", "role": "Writing to his associate who has been left in Crete to establish church order — the letter is the shortest of the Pastorals and the most tightly focused on the connection between sound doctrine and godly conduct"},
      {"name": "Titus", "role": "Paul's Gentile associate (Gal 2:3) entrusted with some of the most demanding assignments in the Pauline mission: Corinth, Crete, and eventually Dalmatia (2 Tim 4:10)"}
    ],
    "context": "Titus was written c. AD 63-65 to Paul's associate left in Crete to appoint elders in every town (1:5) and deal with false teachers. The Cretan context — Cretans had a poor reputation in the ancient world (1:12, Paul quotes Epimenides) — makes the letter's emphasis on transformation by the gospel particularly pointed: the gospel produces a new kind of people even in unpromising soil.",
    "christ_connection": "Titus contains two of the NT's most lyrical descriptions of the Incarnation and its purpose: 'the grace of God has appeared, bringing salvation for all people, training us to renounce ungodliness and worldly passions and to live self-controlled, upright, and godly lives in the present age, waiting for our blessed hope, the appearing of the glory of our great God and Savior Jesus Christ, who gave himself for us to redeem us from all lawlessness' (2:11-14); and the washing of regeneration and renewal of the Holy Spirit (3:5-7). Both passages link the historical appearing of Christ and the eschatological appearing to come, with the Holy Spirit as the present agent of transformation in between.",
    "key_verses": [
      {"ref": "Titus 2:11-13", "note": "The grace of God has appeared bringing salvation and training us... waiting for our blessed hope, the appearing of our great God and Savior Jesus Christ — the gospel as both past appearing and future hope"},
      {"ref": "Titus 3:5", "note": "'He saved us... by the washing of regeneration and renewing of the Holy Spirit, whom he poured out on us richly through Jesus Christ our Savior' — the Trinitarian account of salvation applied to baptism and new birth"}
    ],
    "themes_detail": [
      {"title": "The Connection Between Doctrine and Life", "text": "Titus is the NT's most concentrated treatment of how sound theology produces good works. The letter moves repeatedly between doctrinal affirmation and practical exhortation: elders must hold firm to the trustworthy word (1:9); the false teachers' corruption is theological at root ('they profess to know God, but they deny him by their works', 1:16); the grace of God that appeared trains us to live godly lives (2:11-12); the people of God are to be zealous for good works because Christ gave himself to redeem them from lawlessness (2:14). Orthodoxy without orthopraxy is not orthodoxy — it is a contradiction in terms."},
      {"title": "Church Order and Character in Hostile Environments", "text": "The elder qualifications in Titus 1:6-9 share much with 1 Timothy 3 but are applied to Crete — a specific environment of moral difficulty. The emphasis on being above reproach, not arrogant, not quick-tempered, not a drunkard — are all counter-cultural virtues in a context where the surrounding culture practiced the vices. The appointment of qualified elders is not administrative tidying but the establishment of visible character witnesses whose lives contradict the cultural stereotypes and demonstrate the gospel's transforming power. The church's credibility is inseparable from its leaders' character."},
      {"title": "The Appearing of Grace and the Eschatological Hope", "text": "The two 'appearing' passages (2:11-14; 3:4-7) give the letter its eschatological framework: God's grace appeared in the Incarnation (historical); we await the appearing of our great God and Savior (eschatological); and the Spirit is the present agent of transformation between these two poles. This 'already-not yet' structure means that Christian ethics is eschatologically motivated: we live 'self-controlled, upright, and godly lives in the present age' (2:12) precisely because we are 'waiting for our blessed hope' (2:13). The present life is shaped by both what Christ has already appeared to do and what he will appear to complete."},
      {"title": "Regeneration and the Work of the Holy Spirit", "text": "Titus 3:4-7 is one of the NT's most Trinitarian soteriological statements: God our Savior saved us according to his mercy, through the washing of regeneration and renewal of the Holy Spirit, whom he poured out on us richly through Jesus Christ our Savior, so that being justified by his grace we might become heirs according to the hope of eternal life. Regeneration (new birth) and renewal (ongoing transformation) are both Spirit's work, accomplished by the poured-out Spirit mediated through Christ, grounded in the Father's mercy and completed in justification. The entire Trinitarian economy of salvation is present in three verses."}
    ]
  },

  "philemon": {
    "key_people": [
      {"name": "Paul", "role": "Writes as an old man and prisoner (v. 9), using his relationship with Philemon rather than his apostolic authority to make the most sensitive and socially explosive request of any of his letters"},
      {"name": "Philemon", "role": "A house-church host in Colossae, a convert of Paul's, and Onesimus's owner — Paul's appeal to him is a masterpiece of persuasion that both respects his freedom and makes refusal nearly impossible"},
      {"name": "Onesimus", "role": "The runaway slave who has become a Christian through Paul's ministry in prison, and whom Paul sends back with this letter requesting his freedom — 'no longer as a slave, but better than a slave, as a dear brother' (v. 16)"}
    ],
    "context": "Philemon was written c. AD 60-62 during the same Roman imprisonment as Colossians (Onesimus is named in both). It is a private letter about a specific case: Onesimus, a slave belonging to Philemon, had run away, met Paul in Rome, been converted, and now Paul is sending him back with a request for his freedom. It is the NT's most direct engagement with the institution of slavery.",
    "christ_connection": "Paul's appeal to Philemon is explicitly grounded in the 'in Christ' reality: Onesimus is Paul's child in the faith (v. 10), useful to Paul as he formerly was not (v. 11), and 'no longer a slave, but better than a slave, as a dear brother — dear to me, but even dearer to you, both as a fellow man and as a brother in the Lord' (v. 16). The one-new-humanity principle of Galatians 3:28 is here applied in a concrete pastoral case: if Christ has made Philemon and Onesimus brothers, the institution that defines them as master and slave is incompatible with their new identity. Paul charges Onesimus's debt to his own account (vv. 18-19) — a transparent image of Christ's imputed righteousness.",
    "key_verses": [
      {"ref": "Philemon 15-16", "note": "Onesimus was parted from you for a while so that you might have him back forever, no longer as a slave but as a dear brother — the gospel's transformation of the slave-master relationship"},
      {"ref": "Philemon 18-19", "note": "'If he has wronged you at all, or owes you anything, charge that to my account. I, Paul, write this with my own hand: I will repay it' — Paul's personal guarantee, a clear image of substitutionary imputation"}
    ],
    "themes_detail": [
      {"title": "The Gospel's Subversion of Social Structures", "text": "Philemon is the NT's most concrete demonstration that the gospel principle of Galatians 3:28 ('neither slave nor free... all one in Christ Jesus') has direct social implications. Paul does not call for the abolition of slavery in Roman society, but he asks Philemon to receive Onesimus 'no longer as a slave, but better than a slave, as a dear brother' (v. 16) — a request that if followed would fundamentally undermine the institution in this specific relationship. Historically, the principle Paul establishes here became one of Christianity's most powerful social forces: you cannot treat your brother in Christ as property."},
      {"title": "Persuasion, Freedom, and the Ethics of Christian Request", "text": "Paul explicitly declines to use his apostolic authority to compel Philemon (vv. 8-9) because he wants Philemon to do good freely, not under compulsion (v. 14). The irony is that by declining to compel he makes refusal nearly impossible — every argument in the letter builds social and theological pressure. This is not manipulation but the Christian ethics of persuasion: appealing to a person's better self and to the truth of the gospel rather than to external authority. The freedom Paul preserves is Philemon's freedom to embody what he already believes — or to reveal the gap between his profession and his practice."},
      {"title": "The Theology of Substitution in a Personal Register", "text": "Verses 17-19 contain an explicit statement of substitutionary accounting: Onesimus owes a debt; Paul offers to bear it personally. This is the grammar of the atonement applied in a commercial transaction: the one with no debt takes on the debt of the one who owes. Paul even adds a parenthetical: 'to say nothing of your owing me even your own self' (v. 19) — reminding Philemon that his own spiritual debt has already been paid, which creates an obligation of generosity. The theology here is not abstract: it is embedded in a real relationship with real financial implications."},
      {"title": "Christian Community Across Social Divisions", "text": "The letter's brevity belies its social radicalism. The house church that meets in Philemon's home (v. 2) includes Onesimus after his conversion — a runaway slave at the table with his owner, both receiving the same Lord's Supper. Paul's vision is not merely individual transformation but a community in which the social hierarchy of the ancient world is not simply reproduced inside the church. The brother-sister language that Paul uses throughout his letters is not metaphorical sentimentality but a claim about the church's actual social constitution: a new family in which the bonds of the Spirit transcend the bonds of Roman social order."}
    ]
  },

  "hebrews": {
    "key_people": [
      {"name": "An Unknown Author", "role": "The most anonymous book in the NT; Origen's verdict — 'only God knows for certain who wrote it' — remains valid; proposed authors include Paul, Apollos, Priscilla, Barnabas, and Luke"},
      {"name": "Jesus Christ as High Priest", "role": "The book's unique christological contribution: Jesus as the great high priest who has passed through the heavens, offered himself as the perfect sacrifice, and ministers in the true heavenly sanctuary — a figure with no parallel in the other NT books"},
      {"name": "The Recipients", "role": "Jewish Christians facing pressure to return to Judaism, addressed throughout with the pastoral urgency of people in danger of fatal spiritual regression"}
    ],
    "context": "Hebrews was written before AD 70 (the temple is described as still functioning) to a community of Jewish Christians who are suffering social pressure and considering returning to Judaism. The author's response is the most sustained piece of biblical theology in the NT: he argues, passage by passage through the OT, that Christ is the superior fulfilment of everything in the Mosaic system — angels, Moses, the Levitical priesthood, the tabernacle, and the sacrificial system. To go back to Judaism is to go back to shadows when the substance has arrived.",
    "christ_connection": "Hebrews is the NT's most extended and detailed exposition of Christ's person and work. He is superior to angels (1:1-2:18), greater than Moses (3:1-4:13), the great high priest who has passed through the heavens (4:14-5:10), the mediator of a better covenant (8:1-13), the one who offered himself as the perfect and once-for-all sacrifice (9:1-10:18), and the founder and perfecter of faith (12:1-2). The Melchizedekian priesthood (7:1-28) is the book's most original christological argument: Jesus holds a permanent, indestructible priesthood that supersedes Aaron's precisely because it is not based on physical descent but on an oath of God.",
    "key_verses": [
      {"ref": "Hebrews 1:1-2", "note": "'Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son' — the hermeneutical principle of the entire book: Christ is the culmination of all prior revelation"},
      {"ref": "Hebrews 4:15-16", "note": "Jesus as high priest who sympathises with our weaknesses because he was tempted as we are, yet without sin — the ground for bold approach to the throne of grace"},
      {"ref": "Hebrews 10:14", "note": "'By a single offering he has perfected for all time those who are being sanctified' — the once-for-all sufficiency of Christ's sacrifice, the theological conclusion of the book's central argument"},
      {"ref": "Hebrews 11:1", "note": "'Now faith is the assurance of things hoped for, the conviction of things not seen' — the definition from which the entire roll call of the faithful in chapter 11 flows"}
    ],
    "themes_detail": [
      {"title": "The Superiority of Christ to All that Preceded Him", "text": "Hebrews 1-10 is a sustained typological argument: everything in the Mosaic system — angels as divine messengers, Moses as covenant mediator, Aaron and the Levitical priests, the tabernacle and its furnishings, the Day of Atonement sacrifice — was a shadow pointing to a superior reality now present in Christ. The argument is not that the OT was wrong but that it was anticipatory: the law had but 'a shadow of the good things to come' (10:1). To return to the shadow when the substance has arrived is not conservatism but failure of understanding — and, pastorally, the road back to the far country."},
      {"title": "The Melchizedekian Priesthood and Its Permanence", "text": "The author's most original christological argument (7:1-28) is drawn from two seemingly minor OT passages: Genesis 14 (Abraham tithing to Melchizedek) and Psalm 110:4 (God's oath: 'You are a priest forever after the order of Melchizedek'). From these he constructs an argument that Jesus holds a priesthood that is prior to, independent of, and superior to the Aaronic line: it is not hereditary, not temporary, and not repeatable. Its superiority lies in the oath of God (whereas the Aaronic priests were appointed by law) and in the resurrection (which makes Jesus a 'priest forever' in a way no Aaronic priest ever was). This is the most detailed christological argument in the NT."},
      {"title": "The New Covenant and Its Better Promises", "text": "Hebrews 8-10 develops the typological argument through the covenant: Jesus is the mediator of a better covenant established on better promises (8:6), specifically the new covenant of Jeremiah 31 whose promises (inward law, universal knowledge of God, complete forgiveness) are precisely what the old covenant's sacrifices could not provide. The Aaronic sacrifices were repeated year after year and therefore could not perfect the worshipper; Christ's self-offering was once for all and has 'perfected for all time those who are being sanctified' (10:14). The application is direct: there are no remaining sacrifices for sin (10:26) — to return to the temple system is to treat Christ's sacrifice as insufficient."},
      {"title": "Faith as the Life of the Pilgrim People", "text": "Chapter 11 is the most famous passage in Hebrews: the roll call of faith, spanning from Abel to the Maccabean martyrs, who all died without receiving what was promised (11:13, 39). Their faith was not disappointed — they were living for a city 'whose designer and builder is God' (11:10), a heavenly homeland (11:16) that they glimpsed from a distance. This eschatological faith is the life of the pilgrim: holding loosely to the present, oriented toward the unseen and the future. The application (12:1-2) is direct: surrounded by this cloud of witnesses, fix your eyes on Jesus, the founder and perfecter of faith, who endured the cross for the joy set before him."}
    ]
  },

  "james": {
    "key_people": [
      {"name": "James, brother of the Lord", "role": "The leader of the Jerusalem church (Acts 15; Gal 1:19; 2:9) whose letter reads like a transcribed sermon collection from the early Jewish-Christian community"},
      {"name": "The Rich and the Poor", "role": "The primary social categories James addresses; the exploitation of the poor by the rich is his most persistent ethical concern and the context for his most severe warnings"}
    ],
    "context": "James was written c. AD 45-49 (possibly the earliest NT letter), by James the brother of Jesus to Jewish Christians scattered in the Diaspora (1:1). The letter shows minimal christological development but maximum ethical intensity, and reads like OT wisdom literature applied to the Christian community. It addresses a gap between profession and practice: people who say they have faith but show no corresponding works.",
    "christ_connection": "James's ethical teaching is intelligible only as an application of Jesus' own teaching — the Sermon on the Mount provides a conceptual matrix for most of the letter's concerns (oaths, pure speech, care for the poor, patience, undivided heart). James's vision of pure religion (1:27) and the law of liberty (1:25; 2:12) reflects Jesus' summary of the law in love. The 'royal law' of 2:8 ('love your neighbour as yourself') is the law of Christ. James's apparently anti-Pauline statement about justification (2:14-26) is not contradicting Paul's justification by faith but addressing a different question: not how one is declared righteous before God, but how authentic faith is distinguished from dead faith.",
    "key_verses": [
      {"ref": "James 1:27", "note": "'Religion that is pure and undefiled before God the Father is this: to visit orphans and widows in their affliction, and to keep oneself unstained from the world' — James's definition of authentic piety: both active mercy and personal holiness"},
      {"ref": "James 2:17", "note": "'So also faith by itself, if it does not have works, is dead' — the letter's central thesis: genuine faith is always a faith that works"},
      {"ref": "James 4:6", "note": "'God opposes the proud but gives grace to the humble' — quoted from Proverbs 3:34; the theological foundation of James's ethics: pride is the root of every problem the letter diagnoses"}
    ],
    "themes_detail": [
      {"title": "Trials, Wisdom, and the Formation of Character", "text": "James opens (1:2-18) with a sustained reflection on trials: they should be counted as joy because they produce steadfastness, which produces maturity and completeness. This is not masochistic but theologically grounded: the same God who allows trials also gives wisdom generously to those who ask in faith (1:5). The connection between trials and wisdom — both of which form character — is the letter's opening theological framework. Christians are not to be surprised by difficulties but to see them as the appointed means of growth toward the maturity that the eschatological vision requires."},
      {"title": "Faith and Works: The Test of Authentic Faith", "text": "James 2:14-26 is the most discussed passage in the letter because of its apparent tension with Paul. James's question — 'can that faith save him?' — refers to a claimed faith that produces no works. His answer is that such faith is not genuine faith but a corpse; it is dead, because genuine faith is always a living trust that expresses itself in action. Abraham's justification in Genesis 15 (credited righteousness through faith) and his offering of Isaac in Genesis 22 are not contradictory but sequential: the faith that was credited as righteousness was proved genuine by the works that followed. Faith without works is not faith that lacks works — it is not faith at all."},
      {"title": "The Tongue and the Power of Speech", "text": "James 3:1-12 is the NT's most extended treatment of the tongue. The tongue is a small member that controls the direction of the whole person, as a bit controls a horse or a rudder controls a ship (3:3-4). It is capable of both blessing and cursing (3:9-10) and cannot be tamed by human effort alone (3:8). This assessment is sobering for teachers (3:1) who exercise disproportionate influence through their words. The theology behind James's concern is that speech reveals character: a freshwater spring cannot produce salt water; a fig tree cannot produce olives. What comes out of the mouth is a diagnostic of what is in the heart."},
      {"title": "Care for the Poor and Prophetic Economics", "text": "James's most severe language is directed at the wealthy who exploit the poor (5:1-6): their wealth has rotted, their garments are moth-eaten, the wages of the harvesters they have withheld cry out to the Lord of hosts. This is not incidental but central to James's vision of covenant community: the poor have been dishonoured (2:6), favoured treatment of the wealthy is partiality that violates the royal law (2:8-9), and the rich who oppress the poor through the court system are condemning and murdering the righteous (5:6). James's economics are the prophetic tradition's economics: God is the patron of the poor, and the treatment of the poor is one of the primary indices of genuine faith."}
    ]
  }
}


def enrich(book_id, extras):
    path = os.path.join(OUT, book_id + '.json')
    if not os.path.exists(path):
        print(f'  SKIP  {book_id} (file not found)')
        return
    with open(path, encoding='utf-8') as f:
        data = json.load(f)
    if 'key_people' in data:
        print(f'  skip  {book_id} (already enriched)')
        return
    for key in ('key_people', 'context', 'christ_connection', 'key_verses', 'themes_detail'):
        if key in extras:
            data[key] = extras[key]
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f'  enriched: {book_id}')


for book_id, extras in ENRICHMENTS.items():
    enrich(book_id, extras)

print(f'\nDone — {len(ENRICHMENTS)} books processed: {", ".join(ENRICHMENTS.keys())}')
